func (c *current) onProgram1(rows any) (any, error) {
	p := pp(c)
	for _, r := range toAnySlice(rows) {
		sl := r.([]any)
		if sl[1] != nil {
			p.prog.Append(sl[1].(ast.Node))
		}
	}
	return p.prog, nil
}

func (p *parser) callonProgram1() (any, error) {
	stack := p.vstack[len(p.vstack)-1]
	_ = stack
	return p.cur.onProgram1(stack["rows"])
}

