func (c *current) onForStmt1(val any) (any, error) {
	switch v := val.(type) {
	case *ast.BlockStmt:
		return &ast.ForStmt{Pos: ast.Pos(c.pos.offset), Body: v}, nil
	case forParts:
		stmt := &ast.ForStmt{Pos: ast.Pos(c.pos.offset), Cond: v.Cond, Body: v.Body}
		if v.Init != nil {
			stmt.Init = v.Init.(ast.Stmt)
		}
		if v.Post != nil {
			stmt.Post = v.Post.(ast.Stmt)
		}
		return stmt, nil
	}
	panic("unreachable")
}

