func (c *current) onFnCore1(params, rt, body any) (any, error) {
	p := pp(c)
	lit := &ast.FuncLit{Pos: ast.Pos(c.pos.offset), Signature: &ast.FuncType{Pos: ast.Pos(c.pos.offset)}}
	if params != nil {
		raw := params.([]any)
		// first element is direct paramDef
		pd := raw[0].(paramDef)
		lit.Args = append(lit.Args, &ast.Ident{Pos: ast.Pos(pd.pos), Value: pd.name})
		if pd.typ != nil {
			lit.Signature.ArgsType = append(lit.Signature.ArgsType, pd.typ)
		} else {
			lit.Signature.ArgsType = append(lit.Signature.ArgsType, &ast.NumberType{Pos: ast.Pos(pd.pos)})
		}
		// rest elements are [_, ',', _, paramDef]
		for _, r := range raw[1:] {
			pd := r.([]any)[3].(paramDef)
			lit.Args = append(lit.Args, &ast.Ident{Pos: ast.Pos(pd.pos), Value: pd.name})
			if pd.typ != nil {
				lit.Signature.ArgsType = append(lit.Signature.ArgsType, pd.typ)
			} else {
				lit.Signature.ArgsType = append(lit.Signature.ArgsType, &ast.NumberType{Pos: ast.Pos(pd.pos)})
			}
		}
	}
	checkDuplicateParams(p, lit.Args)
	if rt != nil {
		lit.Signature.ResultType = rt.(ast.ExprType)
	} else {
		lit.Signature.ResultType = &ast.NumberType{Pos: ast.Pos(c.pos.offset)}
	}
	lit.Body = body.(*ast.BlockStmt)
	return lit, nil
}

func (p *parser) callonFnCore1() (any, error) {
	stack := p.vstack[len(p.vstack)-1]
	_ = stack
	return p.cur.onFnCore1(stack["params"], stack["rt"], stack["body"])
}

